challenge.referenceSolution:
#include <print>
#include <stdexcept>
#include <string_view>
#include <array>

struct Entry {
    std::string_view key;
    int value;
};

constexpr std::array<Entry, 4> table = {{
    {"width",  800},
    {"height", 600},
    {"depth",  32},
    {"fps",    60},
}};

constexpr int lookup(std::string_view key) {
    for (const auto& e : table)
        if (e.key == key) return e.value;
    throw std::out_of_range("key not found");
}

constexpr int get_or(std::string_view key, int fallback) {
    try {
        return lookup(key);
    } catch (const std::out_of_range&) {
        return fallback;
    }
}

int main() {
    constexpr int w = get_or("width",   0);
    constexpr int h = get_or("height",  0);
    constexpr int x = get_or("missing", -1);
    std::print("width={} height={} missing={}\n", w, h, x);
}

lessons.theory:
## Транзитное выделение памяти (transient allocation)

C++20 открыл путь: `std::vector` и `std::string` теперь могут работать внутри `constexpr`-функций. Секрет — правило **транзитного выделения**: `constexpr`-оценка может выделять память через `operator new`, но к моменту завершения оценки вся выделенная память должна быть освобождена. Иными словами, вы не можете «вытащить» `constexpr std::vector<int>` как глобальную константу — её аллокация не выживет вне оценки. Но вы можете создать вектор внутри `constexpr`-функции, выполнить любые операции и вернуть **результат** в виде литерального типа (`int`, `std::array`, пользовательский тип без указателей).

```cpp
// ОШИБКА: аллокация «вытекает» из оценки
constexpr std::vector<int> V = {1, 2, 3};  // ill-formed!

// OK: аллокация транзитная — освобождается при выходе из функции
constexpr int sum() {
    std::vector<int> v = {1, 2, 3};
    int s = 0;
    for (int x : v) s += x;
    return s;  // только int выходит наружу
}
constexpr int S = sum();  // S == 6
```

## Что добавил P3372

C++26 расширяет поддержку `constexpr` на следующие контейнеры и адаптеры:

| Контейнер / адаптер | Статус в C++26 |
|---|---|
| `std::vector`, `std::string` | constexpr с C++20 |
| `std::flat_map`, `std::flat_set` | **constexpr с C++26 (P3372)** |
| `std::flat_multimap`, `std::flat_multiset` | **constexpr с C++26 (P3372)** |
| `std::bitset` | **полностью constexpr с C++26** |
| `std::span`, `std::mdspan` | **constexpr-конструкторы с C++26** |
| `std::stack`, `std::queue`, `std::priority_queue` | **constexpr в стандарте C++26** |
| `std::deque` | constexpr в стандарте C++26 |

**Что по-прежнему НЕ является constexpr в C++26:** `std::list`, `std::map`, `std::set`, `std::unordered_map`, `std::unordered_set` и их `multi`-варианты. Причина — node-based структура (каждый элемент — отдельная аллокация с указателем) конфликтует с ограничениями `constexpr`-оценки на работу с адресами.

## std::flat_map и std::flat_set как constexpr-инструменты

`std::flat_map` и `std::flat_set` (C++23) хранят данные в двух `std::vector`-ах: отдельно ключи, отдельно значения. Именно поэтому они так хорошо ложатся в `constexpr`-мир — лежат на вершине уже constexpr-совместимого `std::vector`. Lookup выполняется бинарным поиском по отсортированному ключевому вектору.

```cpp
constexpr int lookup(std::string_view name) {
    std::flat_map<std::string_view, int> tbl = {
        {"alpha", 1}, {"beta", 2}, {"gamma", 3}
    };
    auto it = tbl.find(name);
    return (it != tbl.end()) ? it->second : -1;
}
constexpr int a = lookup("beta");  // a == 2
```

Обратите внимание: `flat_map` сортирует ключи при построении — это происходит на этапе компиляции, обеспечивая полностью нулевые рантайм-издержки.

## std::bitset — полностью constexpr в C++26

`std::bitset<N>` с фиксированным размером шаблонного параметра всегда хранился в стеке (без аллокаций). В C++26 все его методы помечены `constexpr`, что делает `bitset` особенно удобным для компайл-тайм флагового программирования — вычисления масок, подсчёта флагов, проверки условий:

```cpp
constexpr auto FLAGS = [] {
    std::bitset<8> b;
    b.set(0);   // флаг A
    b.set(3);   // флаг D
    b.set(7);   // флаг H
    return b;
}();
static_assert(FLAGS.count() == 3);
static_assert(FLAGS.test(3));
```

## std::span — constexpr-вид без владения

`std::span` никогда не владеет памятью — он лишь хранит указатель и размер. В C++26 его конструкторы объявлены `constexpr`, что позволяет создавать spans на этапе компиляции над `constexpr`-массивами или другими contiguous-диапазонами. Это особенно полезно для передачи compile-time данных в constexpr-функции без копирования:

```cpp
constexpr int DATA[] = {10, 20, 30};
constexpr std::span<const int> VIEW(DATA);
constexpr int FIRST = VIEW.front();  // == 10
```

## consteval и constexpr-контейнеры

`consteval`-функция гарантированно выполняется только на этапе компиляции — компилятор не выпустит для неё рантайм-код. Это идеальная оболочка для сложных compile-time вычислений с контейнерами: внутри `consteval` можно свободно использовать `flat_map`, `vector`, `bitset` и т. д., а результат возвращать как `std::array` или другой литеральный тип.

## Чек-лист нюансов

- **Транзитное выделение**: `constexpr std::vector<int> V = {…}` на уровне пространства имён — **ill-formed**. Вектор как локальная переменная внутри `constexpr`-функции — OK, если результат функции не содержит указателей.
- **Адаптеры с `std::deque` по умолчанию**: `std::stack<int>` использует `std::deque<int>` как underlying container. Если `std::deque` ещё не constexpr в вашем компиляторе — используйте явную специализацию: `std::stack<int, std::vector<int>>`. Стандарт уже разрешает это.
- **`std::list`, `std::map`, `std::set`, `std::unordered_*`** — по-прежнему не constexpr. Попытка использовать их в constexpr-контексте — ошибка компиляции.
- **Результат должен быть литеральным типом**: чтобы `constexpr`-переменная могла хранить результат функции, тип должен быть литеральным (нет невиртуальных деструкторов, нет указателей на выделенную память). `std::array<T, N>` и пользовательские агрегаты без указателей — подходят; `std::vector` — нет.
- **Взаимодействие с шаблонами**: передача `constexpr`-вычисленных значений как NTTP (non-type template parameter) требует, чтобы тип был *structural*. `int`, `std::array<int,N>` — structural; `std::vector` — нет.

examples.code:
#include <flat_map>
#include <string_view>
#include <print>

// flat_map is used transiently inside a constexpr function.
// Only a plain int (a literal type) escapes.
constexpr int get_opcode(std::string_view name) {
    std::flat_map<std::string_view, int> opcodes = {
        {"NOP", 0}, {"ADD", 1}, {"SUB", 2}, {"MUL", 3}, {"DIV", 4}
    };
    auto it = opcodes.find(name);
    if (it != opcodes.end()) return it->second;
    return -1;
}

constexpr std::size_t count_opcodes() {
    std::flat_map<std::string_view, int> opcodes = {
        {"NOP", 0}, {"ADD", 1}, {"SUB", 2}, {"MUL", 3}, {"DIV", 4}
    };
    return opcodes.size();
}

int main() {
    constexpr int add_op  = get_opcode("ADD");
    constexpr int mul_op  = get_opcode("MUL");
    constexpr int bad_op  = get_opcode("JMP");
    constexpr std::size_t total = count_opcodes();

    std::print("ADD={}\n", add_op);
    std::print("MUL={}\n", mul_op);
    std::print("JMP={}\n", bad_op);
    std::print("total opcodes={}\n", total);
}

#include <bitset>
#include <print>

enum Feature : std::size_t {
    SSE2   = 0,
    AVX    = 1,
    AVX512 = 2,
    AES    = 3,
    SHA    = 4,
    BMI2   = 5,
};

constexpr std::bitset<8> make_mask(bool has_avx, bool has_aes) {
    std::bitset<8> flags;
    flags.set(SSE2);               // always present on x86-64
    if (has_avx) flags.set(AVX);
    if (has_aes) flags.set(AES);
    flags.set(BMI2);
    return flags;
}

// Both values computed at compile time
constexpr auto MODERN_CPU = make_mask(true,  true);
constexpr auto BASIC_CPU  = make_mask(false, false);

int main() {
    std::print("modern CPU flags: {}\n", MODERN_CPU.to_string());
    std::print("modern has AVX:   {}\n", MODERN_CPU.test(AVX));
    std::print("modern has AES:   {}\n", MODERN_CPU.test(AES));
    std::print("basic CPU flags:  {}\n", BASIC_CPU.to_string());
    std::print("active features:  {}\n", MODERN_CPU.count());
}

#include <vector>
#include <array>
#include <print>

// consteval: the function MUST execute at compile time;
// the compiler generates no runtime code for it.
consteval std::array<int, 5> top5_primes_under(int limit) {
    // vector as a working buffer — transient allocation
    std::vector<bool> sieve(static_cast<std::size_t>(limit), true);
    sieve[0] = sieve[1] = false;
    for (int i = 2; i < limit; ++i)
        if (sieve[static_cast<std::size_t>(i)])
            for (int j = i * 2; j < limit; j += i)
                sieve[static_cast<std::size_t>(j)] = false;

    std::vector<int> primes;
    for (int i = limit - 1; i >= 2 && static_cast<int>(primes.size()) < 5; --i)
        if (sieve[static_cast<std::size_t>(i)])
            primes.push_back(i);

    // Return std::array — a literal type; no allocation escapes
    std::array<int, 5> result{};
    for (int i = 0; i < 5; ++i)
        result[static_cast<std::size_t>(i)] = primes[static_cast<std::size_t>(i)];
    return result;
}

constexpr auto PRIMES = top5_primes_under(50);

int main() {
    std::print("Top 5 primes under 50 (descending):\n");
    for (int p : PRIMES)
        std::print("  {}\n", p);
}

#include <span>
