struct OldTaggedInt {
    union { int val; char pad; };
    bool active;  // explicit discriminant required

    constexpr OldTaggedInt()    : pad(0),   active(false) {}
    constexpr OldTaggedInt(int v) : val(v), active(true)  {}
    constexpr bool has_val() const { return active; }
    constexpr int  get_val() const { return val; }
};

// New approach (C++26): is_within_lifetime instead of bool flag
struct NewTaggedInt {
    union { int val; char pad; };

    constexpr NewTaggedInt()    : pad(0) {}
    constexpr NewTaggedInt(int v) { std::construct_at(&val, v); }

    consteval bool has_val() const { return __builtin_is_within_lifetime(&val); }
    consteval int  get_val() const { return val; }
};

consteval int old_sum(OldTaggedInt a, OldTaggedInt b) {
    return (a.has_val() ? a.get_val() : 0) + (b.has_val() ? b.get_val() : 0);
}
consteval int new_sum(NewTaggedInt a, NewTaggedInt b) {
    return (a.has_val() ? a.get_val() : 0) + (b.has_val() ? b.get_val() : 0);
}

int main() {
    static_assert(old_sum(OldTaggedInt{7}, OldTaggedInt{}) == 7);
    static_assert(new_sum(NewTaggedInt{7}, NewTaggedInt{}) == 7);
    static_assert(old_sum(OldTaggedInt{3}, OldTaggedInt{4}) == 7);
    static_assert(new_sum(NewTaggedInt{3}, NewTaggedInt{4}) == 7);
