template<typename L, typename R>
struct Either {
    union { L left; R right; };

    constexpr Either() : left{} {}

    static constexpr Either make_left(L val) {
        Either e;
        e.left = val;
        return e;
    }
    static constexpr Either make_right(R val) {
        Either e;
        std::construct_at(&e.right, val);
        return e;
    }

    // Query the active member — without a manual tag!
    consteval bool is_left()  const { return __builtin_is_within_lifetime(&left);  }
    consteval bool is_right() const { return __builtin_is_within_lifetime(&right); }

    consteval L get_left()  const { return left;  }
    consteval R get_right() const { return right; }

    consteval double visit(auto f, auto g) const {
        if (is_left())  return f(left);
        if (is_right()) return g(right);
        return 0.0;
    }
};

consteval double sum_all() {
    auto e1 = Either<int, double>::make_left(42);
    auto e2 = Either<int, double>::make_right(0.5);
    auto e3 = Either<int, double>::make_left(8);

    auto to_double = [](auto v) -> double { return static_cast<double>(v); };
    return e1.visit(to_double, to_double)
         + e2.visit(to_double, to_double)
         + e3.visit(to_double, to_double);
}

int main() {
    constexpr double result = sum_all();
    static_assert(result == 50.5);
    std::print("Either result = {}\n", result);
}

